import { MassSpringLog } from './MassSpringLog';

// PHYSICS_SUB_STEPS: Number of physics iterations per frame.
// Increase -> Simulation is stiffer, less jiggly, and more stable, but uses more CPU.
// Decrease -> Simulation is more "jelly-like", prone to explosions, but uses less CPU.
const PHYSICS_SUB_STEPS = 6;

const simulator = new MassSpringLog();

let scenarioName = '';
let guidebarOBB: any = null;

// Mock kerf width state
let kerfWidthPercentage = 100;
let smoothedClampingPressure = 0;

let activeToolForce: { particles: number[], direction: { x: number, y: number, z: number }, magnitude: number } | null = null;
let activeWedges: Array<{ id: string, cutIdx: number, depth: number, localBarkNodeL: number, localBarkNodeR: number, pithNodeL: number, pithNodeR: number }> = [];

function testSegmentOBB(
  p0: { x: number; y: number; z: number },
  p1: { x: number; y: number; z: number },
  obb: any
): boolean {
  if (!obb) return false;

  const C = obb.center;
  const u = obb.axes; // array of 3 vectors
  const halfSize = obb.cutHalfSizes || obb.halfSizes;

  // Transform p0 and p1 into OBB local space
  const dx0 = p0.x - C.x;
  const dy0 = p0.y - C.y;
  const dz0 = p0.z - C.z;

  const localP0 = {
    x: dx0 * u[0].x + dy0 * u[0].y + dz0 * u[0].z,
    y: dx0 * u[1].x + dy0 * u[1].y + dz0 * u[1].z,
    z: dx0 * u[2].x + dy0 * u[2].y + dz0 * u[2].z
  };

  const dx1 = p1.x - C.x;
  const dy1 = p1.y - C.y;
  const dz1 = p1.z - C.z;

  const localP1 = {
    x: dx1 * u[0].x + dy1 * u[0].y + dz1 * u[0].z,
    y: dx1 * u[1].x + dy1 * u[1].y + dz1 * u[1].z,
    z: dx1 * u[2].x + dy1 * u[2].y + dz1 * u[2].z
  };

  // Segment midpoint and half-direction
  const m = { x: (localP0.x + localP1.x) * 0.5, y: (localP0.y + localP1.y) * 0.5, z: (localP0.z + localP1.z) * 0.5 };
  const d = { x: localP1.x - localP0.x, y: localP1.y - localP0.y, z: localP1.z - localP0.z };
  const hd = { x: Math.abs(d.x * 0.5), y: Math.abs(d.y * 0.5), z: Math.abs(d.z * 0.5) };

  // Test against AABB faces
  if (Math.abs(m.x) > halfSize.x + hd.x) return false;
  if (Math.abs(m.y) > halfSize.y + hd.y) return false;
  if (Math.abs(m.z) > halfSize.z + hd.z) return false;

  // Test against cross products of segment direction and AABB axes
  const adx = Math.abs(d.x);
  const ady = Math.abs(d.y);
  const adz = Math.abs(d.z);
  const EPS = 1e-6; // Prevents floating-point precision edge cases
  if (Math.abs(m.y * d.z - m.z * d.y) > halfSize.y * adz + halfSize.z * ady + EPS) return false;
  if (Math.abs(m.z * d.x - m.x * d.z) > halfSize.x * adz + halfSize.z * adx + EPS) return false;
  if (Math.abs(m.x * d.y - m.y * d.x) > halfSize.x * ady + halfSize.y * adx + EPS) return false;

  return true;
}

function testPointOBB(p: { x: number; y: number; z: number }, obb: any): boolean {
  if (!obb) return false;

  const C = obb.center;
  const u = obb.axes;
  const halfSize = obb.kerfDetectHalfSizes || obb.cutHalfSizes || obb.halfSizes;

  const dx = p.x - C.x;
  const dy = p.y - C.y;
  const dz = p.z - C.z;

  const rx = Math.abs(dx * u[0].x + dy * u[0].y + dz * u[0].z);
  const ry = Math.abs(dx * u[1].x + dy * u[1].y + dz * u[1].z);
  const rz = Math.abs(dx * u[2].x + dy * u[2].y + dz * u[2].z);

  return rx <= halfSize.x && ry <= halfSize.y && rz <= halfSize.z;
}

self.onmessage = (event: MessageEvent) => {
  const { type, data, buffer } = event.data;

  switch (type) {
    case 'INIT':
      scenarioName = data.scenarioName;
      // Initialize simulator with log configuration centered at (0,1,0)
      simulator.initialize(
        data.log.length,
        data.log.diameter / 2, // Radius = diameter / 2
        data.log.density,
        data.supports,
        { x: 0, y: 1, z: 0 }
      );
      // Reset kerf width and cutting state when initializing scenarios
      kerfWidthPercentage = 100;
      (self as any).cutAfterRingIndex = undefined;
      (self as any).activeCuts = [];
      break;

    case 'SET_TERRAIN':
      simulator.setTerrain(data);
      break;

    case 'UPDATE_SAW_TRANSFORM':
      guidebarOBB = data.guidebarOBB;
      break;

    case 'SET_TOOL_FORCE': {
      if (data.active) {
        const { position, direction, radius, magnitude } = data;
        const affectedParticles = [];
        const r2 = radius * radius;
        for (let i = 0; i < simulator.numParticles; i++) {
          const px = simulator.positions[i * 3];
          const py = simulator.positions[i * 3 + 1];
          const pz = simulator.positions[i * 3 + 2];
          const dx = px - position.x;
          const dy = py - position.y;
          const dz = pz - position.z;
          if (dx * dx + dy * dy + dz * dz <= r2) {
            affectedParticles.push(i);
          }
        }
        activeToolForce = { particles: affectedParticles, direction, magnitude };
      } else {
        activeToolForce = null;
      }
      break;
    }

    case 'POUND_WEDGE': {
      const { cutIdx, isTop, depthIncrement, maxDepth } = data;
      // Find existing wedge
      let wedge = activeWedges.find(w => w.cutIdx === cutIdx && w.id === (isTop ? 'top' : 'bottom'));

      if (!wedge) {
        // Create new wedge locked to current particles
        const ringL = (cutIdx + 1) * simulator.particlesPerRing;
        const ringR = (cutIdx + 2) * simulator.particlesPerRing;

        let bestBarkL = ringL + 9;
        let bestY = isTop ? -Infinity : Infinity;

        for (let i = 0; i < 16; i++) {
          const node = ringL + 9 + i;
          const py = simulator.positions[node * 3 + 1];
          if (isTop ? py > bestY : py < bestY) {
            bestY = py;
            bestBarkL = node;
          }
        }

        const bestBarkR = ringR + 9 + (bestBarkL - (ringL + 9));

        wedge = {
          id: isTop ? 'top' : 'bottom',
          cutIdx,
          depth: 0,
          localBarkNodeL: bestBarkL,
          localBarkNodeR: bestBarkR,
          pithNodeL: ringL,
          pithNodeR: ringR
        };
        activeWedges.push(wedge);
      }

      wedge.depth = Math.min(wedge.depth + depthIncrement, maxDepth);
      break;
    }

    case 'REMOVE_WEDGE': {
      activeWedges = activeWedges.filter(w => !(w.cutIdx === data.cutIdx && w.id === data.id));
      break;
    }

    case 'INSERT_ENDCAPS': {
      const { guidebarCenter, normal, kerfWidth, kerfPadding } = data;
      console.log("physics.worker.ts: INSERT_ENDCAPS message received!", { guidebarCenter, normal, kerfWidth, kerfPadding });
      try {
        const C = guidebarCenter;
        const N = { x: normal.x, y: normal.y, z: normal.z };
        if (N.x < 0) {
          N.x = -N.x;
          N.y = -N.y;
          N.z = -N.z;
        }
        let bestR = -1;
        let bestT = 0.5;
        for (let r = 0; r < simulator.numRings - 1; r++) {
          const p1x = simulator.positions[(r * simulator.particlesPerRing) * 3];
          const p1y = simulator.positions[(r * simulator.particlesPerRing) * 3 + 1];
          const p1z = simulator.positions[(r * simulator.particlesPerRing) * 3 + 2];
          const p2x = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3];
          const p2y = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3 + 1];
          const p2z = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3 + 2];

          const d1 = N.x * (p1x - C.x) + N.y * (p1y - C.y) + N.z * (p1z - C.z);
          const d2 = N.x * (p2x - C.x) + N.y * (p2y - C.y) + N.z * (p2z - C.z);

          if (d1 * d2 <= 0 && Math.abs(d1 - d2) > 0.0001) {
            bestT = Math.abs(d1) / (Math.abs(d1) + Math.abs(d2));
            bestR = r;
            break;
          }
        }
        if (bestR === -1) {
          console.warn("physics.worker.ts: Could not find a valid ring to cut");
          break;
        }
        simulator.kerfCollisionMargin = kerfWidth * 0.85;
        const cutAfterRingIndex = simulator.insertEndcaps(bestR, bestT, N, kerfWidth, kerfPadding !== undefined ? kerfPadding : 0.001);
        console.log("physics.worker.ts: insertEndcaps completed, cutAfterRingIndex =", cutAfterRingIndex);
        const activeCuts: number[] = (self as any).activeCuts || [];
        for (let i = 0; i < activeCuts.length; i++) {
          if (activeCuts[i] >= cutAfterRingIndex) {
            activeCuts[i] += 2;
          }
        }
        activeCuts.push(cutAfterRingIndex);
        activeCuts.sort((a, b) => a - b);
        (self as any).activeCuts = activeCuts;
      } catch (err) {
        console.error("physics.worker.ts: Error in insertEndcaps:", err);
      }
      break;
    }

    case 'STEP': {
      try {
        const deltaTime = data.deltaTime;
        const throttleActive = data.throttleActive;

        if (data.guidebarOBB !== undefined) {
          guidebarOBB = data.guidebarOBB;
        }
        if (data.gravity !== undefined) {
          simulator.gravityY = -data.gravity;
        }

        // Auto-insert endcaps on touch if touching an uncut section
        if (throttleActive && guidebarOBB) {
          const activeCuts: number[] = (self as any).activeCuts || [];

          let touchedNew = false;
          for (const spring of simulator.springs) {
            if (spring.L0 < 0) continue;
            const p0 = { x: simulator.positions[spring.i1 * 3], y: simulator.positions[spring.i1 * 3 + 1], z: simulator.positions[spring.i1 * 3 + 2] };
            const p1 = { x: simulator.positions[spring.i2 * 3], y: simulator.positions[spring.i2 * 3 + 1], z: simulator.positions[spring.i2 * 3 + 2] };
            if (testSegmentOBB(p0, p1, guidebarOBB)) {
              let isCrossKerf = false;
              for (const cutIdx of activeCuts) {
                const P_insert = (cutIdx + 1) * simulator.particlesPerRing;
                if ((spring.i1 < P_insert && spring.i2 >= P_insert + 50) ||
                  (spring.i2 < P_insert && spring.i1 >= P_insert + 50)) {
                  isCrossKerf = true;
                  break;
                }
              }

              if (!isCrossKerf) {
                const ring1 = Math.floor(spring.i1 / simulator.particlesPerRing);
                const ring2 = Math.floor(spring.i2 / simulator.particlesPerRing);
                if (Math.abs(ring1 - ring2) === 1 && spring.k === 1.0) { // k=1.0 is grain
                  let nearKerf = false;
                  for (const cutIdx of activeCuts) {
                    if (ring1 >= cutIdx - 1 && ring1 <= cutIdx + 4) nearKerf = true;
                    if (ring2 >= cutIdx - 1 && ring2 <= cutIdx + 4) nearKerf = true;
                  }
                  if (!nearKerf) {
                    touchedNew = true;
                    break;
                  }
                }
              }
            }
          }

          if (touchedNew) {
            console.log("physics.worker.ts: Auto-inserting endcaps at new location.");
            const C = guidebarOBB.center;
            const N = { x: guidebarOBB.axes[0].x, y: guidebarOBB.axes[0].y, z: guidebarOBB.axes[0].z };
            if (N.x < 0) {
              N.x = -N.x;
              N.y = -N.y;
              N.z = -N.z;
            }
            let bestR = -1;
            let bestT = 0.5;
            for (let r = 0; r < simulator.numRings - 1; r++) {
              const p1x = simulator.positions[(r * simulator.particlesPerRing) * 3];
              const p1y = simulator.positions[(r * simulator.particlesPerRing) * 3 + 1];
              const p1z = simulator.positions[(r * simulator.particlesPerRing) * 3 + 2];
              const p2x = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3];
              const p2y = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3 + 1];
              const p2z = simulator.positions[((r + 1) * simulator.particlesPerRing) * 3 + 2];

              const d1 = N.x * (p1x - C.x) + N.y * (p1y - C.y) + N.z * (p1z - C.z);
              const d2 = N.x * (p2x - C.x) + N.y * (p2y - C.y) + N.z * (p2z - C.z);

              if (d1 * d2 <= 0 && Math.abs(d1 - d2) > 0.0001) {
                bestT = Math.abs(d1) / (Math.abs(d1) + Math.abs(d2));
                bestR = r;
                break;
              }
            }
            if (bestR !== -1) {
              const kerfWidth = data.kerfWidth !== undefined ? data.kerfWidth : 0.06;
              const kerfPadding = data.kerfPadding !== undefined ? data.kerfPadding : 0.001;
              simulator.kerfCollisionMargin = kerfWidth * 0.85;
              const cutAfterRingIndex = simulator.insertEndcaps(bestR, bestT, N, kerfWidth, kerfPadding);

              for (let i = 0; i < activeCuts.length; i++) {
                if (activeCuts[i] >= cutAfterRingIndex) activeCuts[i] += 2;
              }
              activeCuts.push(cutAfterRingIndex);
              activeCuts.sort((a, b) => a - b);
              (self as any).activeCuts = activeCuts;
            }
          }
        }

        // Compile lists of intersecting elements for debugging overlays AND perform cutting logic
        const intersectingSprings: number[] = [];
        const intersectingEndcapNodes: number[] = [];
        const activeCuts: number[] = (self as any).activeCuts || [];

        if (guidebarOBB) {
          for (let sIdx = 0; sIdx < simulator.springs.length; sIdx++) {
            const spring = simulator.springs[sIdx];
            if (spring.L0 < 0) continue;

            const p0 = { x: simulator.positions[spring.i1 * 3], y: simulator.positions[spring.i1 * 3 + 1], z: simulator.positions[spring.i1 * 3 + 2] };
            const p1 = { x: simulator.positions[spring.i2 * 3], y: simulator.positions[spring.i2 * 3 + 1], z: simulator.positions[spring.i2 * 3 + 2] };

            if (testSegmentOBB(p0, p1, guidebarOBB)) {
              let isCrossKerf = false;
              for (const cutIdx of activeCuts) {
                const P_insert = (cutIdx + 1) * simulator.particlesPerRing;
                const splitIdx = P_insert + 25;
                if ((spring.i1 < splitIdx && spring.i2 >= splitIdx) ||
                  (spring.i2 < splitIdx && spring.i1 >= splitIdx)) {
                  isCrossKerf = true;
                  break;
                }
              }

              if (activeCuts.length === 0 || isCrossKerf) {
                intersectingSprings.push(spring.i1, spring.i2);
                if (throttleActive && isCrossKerf) simulator.breakSpring(spring);
              }
            }
          }
        }

        // Apply external tool forces
        let activeToolPosition = null;
        if (simulator.externalForces) {
          simulator.externalForces.fill(0);
          if (activeToolForce && activeToolForce.particles.length > 0) {
            let sumX = 0, sumY = 0, sumZ = 0;
            const perParticleMagnitude = activeToolForce.magnitude / activeToolForce.particles.length;
            const fx = activeToolForce.direction.x * perParticleMagnitude;
            const fy = activeToolForce.direction.y * perParticleMagnitude;
            const fz = activeToolForce.direction.z * perParticleMagnitude;

            for (const pIdx of activeToolForce.particles) {
              simulator.externalForces[pIdx * 3] = fx;
              simulator.externalForces[pIdx * 3 + 1] = fy;
              simulator.externalForces[pIdx * 3 + 2] = fz;

              sumX += simulator.positions[pIdx * 3];
              sumY += simulator.positions[pIdx * 3 + 1];
              sumZ += simulator.positions[pIdx * 3 + 2];
            }

            activeToolPosition = {
              x: sumX / activeToolForce.particles.length,
              y: sumY / activeToolForce.particles.length,
              z: sumZ / activeToolForce.particles.length
            };
          }
        }

        const subDt = deltaTime / PHYSICS_SUB_STEPS;
        let totalStepPressure = 0;

        const frictionDebugData = data.debugFrictionForces ? { nodes: [] as number[], vectors: [] as { x: number, y: number, z: number }[] } : undefined;

        for (let s = 0; s < PHYSICS_SUB_STEPS; s++) {
          simulator.integrateAndFracture(subDt);
          simulator.updateDynamicGrid();
          if (data.resolveCollisions !== false) {
            totalStepPressure += simulator.resolveCollisions(guidebarOBB, data.enableEndcapFriction, data.debugFrictionForces, frictionDebugData, activeWedges);
          }
          simulator.solveSprings();
        }

        // Apply low pass filter to smooth out physics jitter
        smoothedClampingPressure = smoothedClampingPressure * 0.9 + totalStepPressure * 0.1;

        // Debug spring stretch
        (self as any).stepCount = ((self as any).stepCount || 0) + 1;
        if ((self as any).stepCount % 60 === 0) {
          let maxStretch = 0;
          let brokenCount = 0;
          for (const s of simulator.springs) {
            if (s.L0 < 0) {
              brokenCount++;
              continue;
            }
            const idx1 = s.i1 * 3;
            const idx2 = s.i2 * 3;
            const dx = simulator.positions[idx1] - simulator.positions[idx2];
            const dy = simulator.positions[idx1 + 1] - simulator.positions[idx2 + 1];
            const dz = simulator.positions[idx1 + 2] - simulator.positions[idx2 + 2];
            const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
            const stretch = dist / s.L0;
            if (stretch > maxStretch) maxStretch = stretch;
          }
          console.log(`[Physics Debug] step: ${(self as any).stepCount}, maxStretch: ${maxStretch.toFixed(4)}, broken: ${brokenCount}/${simulator.springs.length}`);
        }

        // Dynamic Bark states per cut
        const activeBarkSegments: boolean[] = [];
        for (const cutIdx of activeCuts) {
          const pPerRing = simulator.particlesPerRing;
          for (let p = 0; p < 16; p++) {
            const nodeLeft = (cutIdx + 1) * pPerRing + 9 + p;
            const nodeRight = (cutIdx + 2) * pPerRing + 9 + p;
            const spring = simulator.springs.find(s =>
              (s.i1 === nodeLeft && s.i2 === nodeRight) ||
              (s.i1 === nodeRight && s.i2 === nodeLeft)
            );
            if (spring && spring.L0 < 0) {
              activeBarkSegments.push(false);
            } else {
              activeBarkSegments.push(true);
            }
          }
        }

        // Map clamping pressure to kerfWidthPercentage (0-100)
        const maxPressure = 0.7; // Threshold for 100% bind (0 kerfWidthPercentage)

        if (guidebarOBB && activeCuts.length > 0) {
          const pressurePercent = (smoothedClampingPressure / maxPressure) * 100;
          if (scenarioName === 'Top Bind') {
            // In top bind scenario, pinch down to 85% to demonstrate bind visually
            kerfWidthPercentage = Math.max(85, Math.min(100, 100 - pressurePercent));
          } else {
            kerfWidthPercentage = Math.max(0, Math.min(100, 100 - pressurePercent));
          }
        } else {
          // Recovery when saw is removed
          kerfWidthPercentage = Math.min(100, kerfWidthPercentage + 30 * deltaTime);
          smoothedClampingPressure = 0; // Reset pressure
        }

        // Calculate intersecting endcap nodes for visual overlays (AFTER simulator update to get latest positions)
        if (guidebarOBB) {
          for (const cutIdx of activeCuts) {
            const pPerRing = simulator.particlesPerRing;
            for (let i = 0; i < pPerRing; i++) {
              const nC1 = (cutIdx + 1) * pPerRing + i;
              const nC2 = (cutIdx + 2) * pPerRing + i;

              const p1 = { x: simulator.positions[nC1 * 3], y: simulator.positions[nC1 * 3 + 1], z: simulator.positions[nC1 * 3 + 2] };
              const p2 = { x: simulator.positions[nC2 * 3], y: simulator.positions[nC2 * 3 + 1], z: simulator.positions[nC2 * 3 + 2] };

              if (testPointOBB(p1, guidebarOBB)) {
                intersectingEndcapNodes.push(nC1);
              }
              if (testPointOBB(p2, guidebarOBB)) {
                intersectingEndcapNodes.push(nC2);
              }
            }
          }
        }

        // Calculate vertex strains for Binding Indicators
        const vertexStrains = new Float32Array(simulator.numParticles);
        const vertexSpringCounts = new Uint8Array(simulator.numParticles);

        for (const spring of simulator.springs) {
          if (spring.L0 < 0) continue;

          if (spring.L0 < 0.05) continue;

          const idx1 = spring.i1 * 3;
          const idx2 = spring.i2 * 3;
          const dx = simulator.positions[idx1] - simulator.positions[idx2];
          const dy = simulator.positions[idx1 + 1] - simulator.positions[idx2 + 1];
          const dz = simulator.positions[idx1 + 2] - simulator.positions[idx2 + 2];
          const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

          const strain = (dist - spring.L0) / spring.L0;

          vertexStrains[spring.i1] += strain;
          vertexSpringCounts[spring.i1]++;

          vertexStrains[spring.i2] += strain;
          vertexSpringCounts[spring.i2]++;
        }

        for (let i = 0; i < simulator.numParticles; i++) {
          if (vertexSpringCounts[i] > 0) {
            vertexStrains[i] /= vertexSpringCounts[i];
          }
        }

        // Dynamic Wedge Removal: check if wedge is loose
        if (activeWedges.length > 0) {
          activeWedges = activeWedges.filter(wedge => {
            const bxL = simulator.positions[wedge.localBarkNodeL * 3];
            const byL = simulator.positions[wedge.localBarkNodeL * 3 + 1];
            const bzL = simulator.positions[wedge.localBarkNodeL * 3 + 2];

            const bxR = simulator.positions[wedge.localBarkNodeR * 3];
            const byR = simulator.positions[wedge.localBarkNodeR * 3 + 1];
            const bzR = simulator.positions[wedge.localBarkNodeR * 3 + 2];

            const dist = Math.sqrt((bxR - bxL) ** 2 + (byR - byL) ** 2 + (bzR - bzL) ** 2);

            // Maximum thickness of wedge is 0.1m (as tested). If distance > 0.12m, it's loose and should drop.
            if (dist > 0.12) {
              console.log(`physics.worker.ts: Wedge ${wedge.id} at kerf ${wedge.cutIdx} fell out! (Gap: ${dist.toFixed(3)}m)`);
              return false; // Remove it
            }
            return true;
          });
        }

        // Calculate independent logs
        let maxSegId = 0;
        let independentLogsCount = 1;
        let particleLogIds: Uint16Array | undefined;
        if (simulator.segmentIds && simulator.springs) {
          for (let i = 0; i < simulator.segmentIds.length; i++) {
            if (simulator.segmentIds[i] > maxSegId) {
              maxSegId = simulator.segmentIds[i];
            }
          }

          const parent = new Uint16Array(maxSegId + 1);
          for (let i = 0; i <= maxSegId; i++) parent[i] = i;

          const findRoot = (i: number): number => {
            if (parent[i] === i) return i;
            parent[i] = findRoot(parent[i]);
            return parent[i];
          };

          const union = (i: number, j: number) => {
            const rootI = findRoot(i);
            const rootJ = findRoot(j);
            if (rootI !== rootJ) {
              parent[rootI] = rootJ;
            }
          };

          for (const spring of simulator.springs) {
            if (spring.L0 < 0) continue;
            const s1 = simulator.segmentIds[spring.i1];
            const s2 = simulator.segmentIds[spring.i2];
            if (s1 !== s2) {
              union(s1, s2);
            }
          }

          const rootToIndex = new Map<number, number>();
          independentLogsCount = 0;
          const segmentToLogMap = new Uint16Array(maxSegId + 1);
          for (let i = 0; i <= maxSegId; i++) {
            const root = findRoot(i);
            if (!rootToIndex.has(root)) {
              rootToIndex.set(root, independentLogsCount++);
            }
            segmentToLogMap[i] = rootToIndex.get(root)!;
          }

          particleLogIds = new Uint16Array(simulator.numParticles);
          for (let i = 0; i < simulator.numParticles; i++) {
            particleLogIds[i] = segmentToLogMap[simulator.segmentIds[i]];
          }
        }

        // Re-create Float32Array on the transferred buffer
        let responseBuffer: ArrayBuffer;
        const requiredFloats = simulator.positions ? simulator.positions.length : 5000;
        if (buffer && buffer.byteLength >= requiredFloats * 4) {
          responseBuffer = buffer;
        } else {
          responseBuffer = new Float32Array(requiredFloats).buffer;
        }

        if (simulator.positions) {
          const floatView = new Float32Array(responseBuffer);
          floatView.set(simulator.positions);
        }

        let dynamicKerfCenterX: number | null = null;
        if (guidebarOBB && activeCuts.length > 0) {
          let closestCutDist = Infinity;
          for (const cutIdx of activeCuts) {
            const leftRing = (cutIdx + 1) * simulator.particlesPerRing;
            const rightRing = (cutIdx + 2) * simulator.particlesPerRing;
            let sumX = 0;
            for (let i = 0; i < simulator.particlesPerRing; i++) {
              sumX += simulator.positions[(leftRing + i) * 3];
              sumX += simulator.positions[(rightRing + i) * 3];
            }
            const kerfCenter = sumX / (simulator.particlesPerRing * 2);
            const dist = Math.abs(guidebarOBB.center.x - kerfCenter);
            if (dist < closestCutDist && dist < 0.2) {
              closestCutDist = dist;
              dynamicKerfCenterX = kerfCenter;
            }
          }
        }

        const wedgesData = activeWedges.map(w => {
          const pxL = simulator.positions[w.localBarkNodeL * 3];
          const pyL = simulator.positions[w.localBarkNodeL * 3 + 1];
          const pzL = simulator.positions[w.localBarkNodeL * 3 + 2];
          const pxR = simulator.positions[w.localBarkNodeR * 3];
          const pyR = simulator.positions[w.localBarkNodeR * 3 + 1];
          const pzR = simulator.positions[w.localBarkNodeR * 3 + 2];

          const barkX = (pxL + pxR) / 2;
          const barkY = (pyL + pyR) / 2;
          const barkZ = (pzL + pzR) / 2;

          const pX_L = simulator.positions[w.pithNodeL * 3];
          const pY_L = simulator.positions[w.pithNodeL * 3 + 1];
          const pZ_L = simulator.positions[w.pithNodeL * 3 + 2];
          const pX_R = simulator.positions[w.pithNodeR * 3];
          const pY_R = simulator.positions[w.pithNodeR * 3 + 1];
          const pZ_R = simulator.positions[w.pithNodeR * 3 + 2];

          const pithX = (pX_L + pX_R) / 2;
          const pithY = (pY_L + pY_R) / 2;
          const pithZ = (pZ_L + pZ_R) / 2;

          const nx = barkX - pithX;
          const ny = barkY - pithY;
          const nz = barkZ - pithZ;
          const len = Math.sqrt(nx * nx + ny * ny + nz * nz) || 1;

          return {
            id: w.id,
            cutIdx: w.cutIdx,
            depth: w.depth,
            isTop: w.id === 'top',
            position: {
              x: barkX - (nx / len) * w.depth,
              y: barkY - (ny / len) * w.depth,
              z: barkZ - (nz / len) * w.depth
            },
            normal: {
              x: nx / len,
              y: ny / len,
              z: nz / len
            }
          };
        });

        self.postMessage({
          type: 'STEP_COMPLETE',
          data: {
            elapsedTime: simulator.elapsedTime,
            kerfWidthPercentage: Math.round(kerfWidthPercentage),
            numParticles: simulator.numParticles,
            numRings: simulator.numRings,
            particlesPerRing: simulator.particlesPerRing,
            cutAfterRingIndex: (self as any).cutAfterRingIndex !== undefined ? (self as any).cutAfterRingIndex : null,
            activeBarkSegments,
            intersectingSprings,
            intersectingEndcapNodes,
            activeCuts,
            vertexStrains,
            activeToolPosition,
            dynamicKerfCenterX,
            frictionDebugData,
            independentLogsCount,
            particleLogIds,
            activeWedges: wedgesData
          },
          buffer: responseBuffer
        }, [responseBuffer, vertexStrains.buffer, ...(particleLogIds ? [particleLogIds.buffer] : [])]);
      } catch (err) {
        console.error("physics.worker.ts: Error in STEP handler:", err);
      }
      break;
    }
  }
};
